def unique_words(text):
    if not text.strip():
        return set()
    return set(text.lower().split())


def common_interests(person_a_interests, person_b_interests):
    return set(person_a_interests) & set(person_b_interests)


def find_exclusive(group_a, group_b):
    set_a = set(group_a)
    set_b = set(group_b)
    return (set_a - set_b, set_b - set_a)


def deduplicate_preserving_order(items):
    seen = set()
    result = []
    for item in items:
        if item not in seen:
            seen.add(item)
            result.append(item)
    return result
